/* let { Keyring,ApiPromise,WsProvider,HttpProvider } = polkadotApi
let { cryptoWaitReady, mnemonicGenerate, mnemonicToMiniSecret, randomAsHex, naclBoxPairFromSecret, signatureVerify } = utilCrypto
let { stringToU8a,u8aToHex } = polkadotUtil */


async function createAddress(mnemonic = '',index = '',network = 42){
  try{
    await utilCrypto.cryptoWaitReady();
    const keyring = new polkadotApi.Keyring({ ss58Format: network, type: 'sr25519' });
    console.log(`mnemonic:${mnemonic}`)
    if(!mnemonic) return false
    let newPair;
    let newMemo;
    if(index === ''){
      newPair = keyring.createFromUri(`${mnemonic}`)
    }else{
      newPair = keyring.createFromUri(`${mnemonic}//${index}`)
    }
    console.log(JSON.stringify(newPair));
    console.log(`address:${newPair.address}`)
    const mnemonicMini = utilCrypto.mnemonicToMiniSecret(mnemonic);
    console.log(polkadotUtil.u8aToHex(mnemonicMini))
    const { publicKey, secretKey } = utilCrypto.naclBoxPairFromSecret(mnemonicMini);
    console.log(`publicKey:${polkadotUtil.u8aToHex(publicKey)}`);
    console.log(`secretKey:${polkadotUtil.u8aToHex(secretKey)}`)

    let walletObj = {
      "seed": mnemonic,
      "address": newPair.address,
      "privateKey": polkadotUtil.u8aToHex(secretKey) + '//' + index
    };
    return walletObj
  }catch(err){
    console.log(err)
  }
}

window.createAddress = createAddress

async function getBalance(address,network = 42,node = 'wss://westend-rpc.polkadot.io') {
    // Construct a provider with the endpoint URL
    const provider = new polkadotApi.WsProvider(node);
    // Create an API instance for Polkadot
    const api = await polkadotApi.ApiPromise.create({ provider });
    const balance = await api.query.system.account(address);
    return balance;
}

window.getBalance = getBalance;

async function privateKeyWallet(privateKey,network = 42){
    await utilCrypto.cryptoWaitReady();
    const keyring = new polkadotApi.Keyring({ ss58Format: network, type: 'sr25519' });
    const hexPair = keyring.addFromUri(privateKey);
    return hexPair
}

window.privateKeyWallet = privateKeyWallet

async function recoverAddress(privateKey,network = 42){
  try{
    const hexPair = await privateKeyWallet(privateKey,network)
    console.log({
		  "address": hexPair.address,
		  "privateKey": privateKey
		})
    return {
		  "address": hexPair.address,
		  "privateKey": privateKey
		}
  }catch(err){
    console.log(err)
  }
}

window.recoverAddress = recoverAddress


async function sendTransaction(address, privateKey,to,amount,network = 42,node = 'wss://westend-rpc.polkadot.io'){
  try{
    const hexPair = await privateKeyWallet(privateKey,network)
    // Construct a provider with the endpoint URL
    const provider = new polkadotApi.WsProvider(node);
    // Create an API instance for Polkadot
    const api = await polkadotApi.ApiPromise.create({ provider });

    const { nonce } = await api.query.system.account(address);

    const txHash = await api.tx.balances.transfer(to,amount*1e12).signAndSend(hexPair,{ nonce });
    console.log(polkadotUtil.u8aToHex(txHash))
    return polkadotUtil.u8aToHex(txHash)
  }catch(err){
    console.log(err)
  }
}

window.sendTransaction = sendTransaction



async function getTransactionFee(privateKey,to,amount,network = 42,node = 'wss://westend-rpc.polkadot.io'){
  try{
    // Construct a provider with the endpoint URL
    const provider = new polkadotApi.WsProvider(node);
    // Create an API instance for Polkadot
    const api = await polkadotApi.ApiPromise.create({ provider });

    let pair = await privateKeyWallet(privateKey,network)
    const { nonce } = await api.query.system.account(pair.address);
    const info = await api.tx.balances.transfer(to,amount)
    let result = await info.paymentInfo(pair,{ nonce });
    let sign = await info.signAsync(pair,{ nonce })
    console.log({
      weight:parseInt(result.weight.toString()),
      size:sign.length
    })
    return {
      weight:parseInt(result.weight.toString()),
      size:sign.length
    }
    
  }catch(err){
    console.log(err)
  }
}
window.getTransactionFee = getTransactionFee


try{
    const {params, callId, method} = plus.webview.currentWebview();

    console.log(method, params, callId);

    if (method && window[method]) {
        window[method].apply(window, params).then((result) => {
            uni.postMessage({ 
                data: { event: callId, data: result }
            });
        });
    }


} catch(err){
	console.log('[console.error]', err)
}




